d;    int idActual = 0;    // Nodos de la capa anterior (arranca con el nodo inicial)    std::vector<int> capaAnterior;    // Nodo de inicio fijo    Lugar* inicio = new Lugar(idActual, "Pueblo Paleta", TipoEvento::NPC);    world.agregarLugar(inicio);    capaAnterior.push_back(idActual);    idActual++;    // Tipos de evento que pueden aparecer en nodos normales    // GYM y LEAGUE se colocan aparte de forma controlada    std::vector<TipoEvento> tiposCombate = {        TipoEvento::WILD_POKEMON,        TipoEvento::WILD_POKEMON,        TipoEvento::TRAINER,        TipoEvento::TRAINER,    };    // Tipos variados para capas normales    std::vector<TipoEvento> tiposNormales = {        TipoEvento::WILD_POKEMON,        TipoEvento::TRAINER,        TipoEvento::SHOP,        TipoEvento::POKEMON_CENTER,        TipoEvento::TREASURE,        TipoEvento::TRAP    };    // Nombres genéricos por tipo para que no todo diga "Nodo X"    auto nombrePorTipo = [](TipoEvento t, int id) -> std::string {        switch (t) {            case TipoEvento::WILD_POKEMON:   return "Ruta " + std::to_string(id);            case TipoEvento::TRAINER:        return "Camino " + std::to_string(id);            case TipoEvento::SHOP:           return "Tienda " + std::to_string(id);            case TipoEvento::POKEMON_CENTER: return "Centro Pokemon";            case TipoEvento::TREASURE:       return "Zona Oculta " + std::to_string(id);            case TipoEvento::TRAP:           return "Cueva Oscura " + std::to_string(id);            default:                         return "Lugar " + std::to_string(id);        }    };    // Capas intermedias: cada capa tiene 2 o 3 nodos    // Los GYMs se colocan en capas fijas: capa 3, 6 y 9 (de 10 capas)    for (int capa = 1; capa < capas; capa++) {        int nodosPorCapa = 2 + (rand() % 2); // 2 o 3 nodos por capa        std::vector<int> capaActual;        bool esCapaGym = (capa == capas / 3) ||                         (capa == (capas * 2) / 3) ||                         (capa == capas - 1);        // En capas de GYM: nodo único obligatorio, no hay donde esquivar        if (esCapaGym) {            Lugar* gym = new Lugar(idActual, "Gimnasio " + std::to_string(idActual), TipoEvento::GYM);            for (int idPrev : capaAnterior) {                Lugar* prev = world.getLugar(idPrev);                if (prev) prev->agregarConexion(idActual);            }            world.agregarLugar(gym);            capaActual.push_back(idActual);            idActual++;        } else {            // Capas normales: 2 o 3 nodos a elegir            for (int n = 0; n < nodosPorCapa; n++) {                // La capa inmediatamente antes de un GYM garantiza combate                bool esPreGym = (capa == 2) || (capa == 5) || (capa == 8);                TipoEvento tipo = esPreGym                    ? tiposCombate[rand() % tiposCombate.size()]                    : tiposNormales[rand() % tiposNormales.size()];                std::string nombre = nombrePorTipo(tipo, idActual);                Lugar* lugar = new Lugar(idActual, nombre, tipo);                for (int idPrev : capaAnterior) {                    Lugar* prev = world.getLugar(idPrev);                    if (prev) prev->agregarConexion(idActual);                }                world.agregarLugar(lugar);                capaActual.push_back(idActual);                idActual++;            }        }        capaAnterior = capaActual;    }    // Nodo final: Liga Pokemon — conectado desde todos los de la última capa    Lugar* liga = new Lugar(idActual, "Liga Pokemon", TipoEvento::LEAGUE);    for (int idPrev : capaAnterior) {        Lugar* prev = world.getLugar(idPrev);        if (prev) prev->agregarConexion(idActual);    }    world.agregarLugar(liga);    return world;}